window.PrtaskGitSync={CheckGitInit:async function(r){try{return await r.getDirectoryHandle(".git"),!0}catch{return!1}},NotifyServiceWorkerGitPull:function(r){navigator.serviceWorker&&navigator.serviceWorker.controller&&navigator.serviceWorker.controller.postMessage({type:"GIT_PULL_COMPLETE",Urls:r})}};